-- ----------------------------
-- Table structure for sp_iot_device_alarm
-- ----------------------------
DROP TABLE IF EXISTS `sp_iot_device_alarm`;
CREATE TABLE `sp_iot_device_alarm`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '告警ID',
  `device_key` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '设备key',
  `alarm_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '告警类型(threshold_exceeded/offline/fault等)',
  `alarm_level` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '告警级别(info/warning/critical)',
  `alarm_title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '告警标题',
  `alarm_message` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '告警内容',
  `alarm_data` json NULL COMMENT '告警详细数据(当前值、阈值等)',
  `is_handled` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '0' COMMENT '是否已处理(0未处理 1已处理)',
  `handle_user_id` bigint NULL DEFAULT NULL COMMENT '处理人ID',
  `handle_time` datetime NULL DEFAULT NULL COMMENT '处理时间',
  `handle_result` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '处理结果',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '告警时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_device_time`(`device_key` ASC, `create_time` ASC) USING BTREE,
  INDEX `idx_level`(`alarm_level` ASC) USING BTREE,
  INDEX `idx_handled`(`is_handled` ASC) USING BTREE,
  INDEX `idx_type`(`alarm_type` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 9 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'IoT设备告警表' ROW_FORMAT = Dynamic;

