INSERT INTO `sp_announcement` VALUES (1, '游泳馆开放时间调整通知', '<h2>尊敬的会员朋友们：</h2><p>为了更好地服务广大顾客，本馆从2026年2月10日起调整开放时间：</p><ul><li><strong>周一至周五：</strong>06:00-22:00</li><li><strong>周六、周日：</strong>07:00-21:00</li></ul><p>请各位会员合理安排游泳时间，如有疑问请咨询前台。</p><p>特此通知！</p>', '1', '2026-02-01 10:00:00', '1', 156, 1, '2026-02-01 09:00:00', NULL, 1, '2026-02-01 09:00:00', NULL, '0');
INSERT INTO `sp_announcement` VALUES (2, '会员充值优惠活动火热进行中', '<h2>🎉 充值优惠活动 🎉</h2><p>为了回馈广大会员的支持，本馆推出充值优惠活动：</p><ul><li>充值500元送50元</li><li>充值1000元送120元</li><li>充值2000元送300元</li><li>充值5000元送800元</li></ul><p><strong>活动时间：</strong>2026年2月1日 - 2026年2月29日</p><p><strong>温馨提示：</strong>赠送金额不可与其他优惠同时使用</p><p>欢迎各位会员前来参与！</p>', '2', '2026-02-03 14:30:00', '1', 342, 1, '2026-02-03 10:00:00', NULL, 1, '2026-02-03 14:30:00', NULL, '0');
INSERT INTO `sp_announcement` VALUES (3, '部分泳道维修公告', '<h2>泳道维修通知</h2><p>为了提升游泳体验，本馆将于以下时间对部分泳道进行维护保养：</p><p><strong>维修时间：</strong>2026年2月8日 - 2月10日</p><p><strong>影响区域：</strong>3号、4号泳道</p><p>维修期间，其他泳道正常开放。给您带来的不便，敬请谅解！</p><p>如有疑问，请联系前台咨询。</p>', '3', '2026-02-05 09:00:00', '1', 89, 1, '2026-02-05 08:00:00', NULL, 1, '2026-02-05 09:00:00', NULL, '0');
INSERT INTO `sp_announcement` VALUES (4, '春节放假通知', '<h2>🧧 2026年春节放假通知 🧧</h2><p>根据国家法定节假日安排，本馆春节放假时间如下：</p><p><strong>放假时间：</strong>2026年2月11日（除夕）- 2月17日（正月初六）</p><p><strong>恢复营业：</strong>2026年2月18日（正月初七）正常营业</p><p>放假期间暂停营业，会员卡有效期自动顺延7天。</p><p>祝各位会员新春快乐，阖家幸福！</p>', '1', '2026-02-04 16:00:00', '1', 268, 1, '2026-02-04 15:00:00', NULL, 2019055215161712641, '2026-02-04 23:58:02', NULL, '0');
INSERT INTO `sp_announcement` VALUES (5, '游泳课程优惠活动', '<h2>🏊 游泳培训班招生啦！</h2><p>专业教练团队，助您掌握游泳技能：</p><ul><li><strong>初级班：</strong>零基础入门，学会蛙泳</li><li><strong>提高班：</strong>提升泳姿，增强体能</li><li><strong>私教课程：</strong>一对一专业指导</li></ul><p><strong>优惠活动：</strong></p><ul><li>新学员首享8折优惠</li><li>老学员续费享7.5折</li><li>推荐好友报名各送1节私教课</li></ul><p>咨询电话：010-12345678</p>', '2', '2026-02-06 11:00:00', '1', 178, 1, '2026-02-06 10:00:00', NULL, 1, '2026-02-06 11:00:00', NULL, '0');
INSERT INTO `sp_announcement` VALUES (6, '水质检测报告公示', '<h2>2026年1月水质检测报告</h2><p>为了保障会员的健康安全，本馆每月进行水质检测，现公示2026年1月检测结果：</p><ul><li><strong>PH值：</strong>7.2-7.6（合格标准：6.5-8.5）</li><li><strong>余氯含量：</strong>0.5mg/L（合格标准：0.3-0.5mg/L）</li><li><strong>浑浊度：</strong>0.3NTU（合格标准：≤1NTU）</li><li><strong>大肠菌群：</strong>未检出</li></ul><p>所有检测指标均符合国家游泳池卫生标准，请各位会员放心游泳。</p>', '1', '2026-02-07 09:30:00', '1', 134, 1, '2026-02-07 08:30:00', NULL, 1, '2026-02-07 09:30:00', NULL, '0');
INSERT INTO `sp_announcement` VALUES (7, '储物柜使用须知', '<h2>🔒 储物柜使用规范通知</h2><p>为了维护场馆秩序，保障会员财物安全，请遵守以下储物柜使用规范：</p><ul><li>请勿将贵重物品存放在储物柜内</li><li>离开时请清空储物柜并带走个人物品</li><li>每日闭馆后将清空所有储物柜</li><li>如有遗失，本馆概不负责</li></ul><p>免费储物柜仅限当日使用，如需长期租用请咨询前台。</p><p>感谢您的配合！</p>', '1', '2026-02-02 10:30:00', '1', 95, 1, '2026-02-02 09:30:00', NULL, 1, '2026-02-02 10:30:00', NULL, '0');
INSERT INTO `sp_announcement` VALUES (8, '会员积分兑换活动', '<h2>🎁 积分兑换好礼</h2><p>好消息！会员积分可以兑换礼品啦：</p><ul><li>500积分：免费游泳券1张</li><li>1000积分：泳帽1个</li><li>2000积分：泳镜1副</li><li>3000积分：泳裤1条</li><li>5000积分：私教课1节</li></ul><p><strong>兑换地点：</strong>前台服务台</p><p><strong>活动时间：</strong>长期有效</p><p>快来兑换您的心仪礼品吧！</p>', '2', '2026-02-08 15:00:00', '1', 223, 1, '2026-02-08 14:00:00', NULL, 1, '2026-02-08 15:00:00', NULL, '0');
INSERT INTO `sp_announcement` VALUES (9, '紧急通知：临时闭馆维护', '<h2>⚠️ 临时闭馆通知</h2><p>因设备突发故障，为确保安全，本馆将于<strong>2026年2月15日 12:00-18:00</strong>临时闭馆进行紧急维修。</p><p>已预约此时段的会员，请前往前台办理改期或退款手续。</p><p>给您带来的不便，我们深表歉意，敬请谅解！</p>', '3', '2026-02-08 16:00:00', '1', 58, 1, '2026-02-08 15:30:00', NULL, 2019055215161712641, '2026-02-07 18:18:35', '紧急通知', '0');
INSERT INTO `sp_announcement` VALUES (10, '春季游泳比赛报名通知', '<h2>🏆 2026年春季游泳比赛</h2><p>为了丰富会员的文体生活，增进友谊，本馆将举办春季游泳比赛：</p><p><strong>比赛时间：</strong>2026年3月15日 14:00</p><p><strong>比赛项目：</strong></p><ul><li>男子组：50米自由泳、100米蛙泳、200米混合泳</li><li>女子组：50米自由泳、100米蛙泳、200米混合泳</li></ul><p><strong>报名条件：</strong>本馆会员均可免费报名参加</p><p><strong>报名时间：</strong>2026年2月10日 - 3月5日</p><p><strong>报名地点：</strong>前台服务台</p><p>奖品丰厚，欢迎踊跃报名！</p>', '2', '2026-02-09 10:00:00', '1', 152, 1, '2026-02-09 09:00:00', NULL, 2019055215161712641, '2026-02-07 18:18:37', NULL, '0');
